import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 14 — Searching","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/14-searching.md","filePath":"chapters/14-searching.md"}'),d={name:"chapters/14-searching.md"};function c(s,e,h,i,n,l){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="chapter-14-—-searching" tabindex="-1">Chapter 14 — Searching <a class="header-anchor" href="#chapter-14-—-searching" aria-label="Permalink to &quot;Chapter 14 — Searching&quot;">​</a></h1><blockquote><p><em>&quot;Stop scrolling. Start searching.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Scrolling through a large file to find something is slow.</p><p>Searching is instant.</p><p>Vim&#39;s search is powerful, fast, and works with the composable command grammar.</p><hr><h1 id="basic-search" tabindex="-1">Basic Search <a class="header-anchor" href="#basic-search" aria-label="Permalink to &quot;Basic Search&quot;">​</a></h1><h2 id="forward-search" tabindex="-1">Forward Search <a class="header-anchor" href="#forward-search" aria-label="Permalink to &quot;Forward Search&quot;">​</a></h2><p>From normal mode, type:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pattern</span></span></code></pre></div><p>Press <strong>Enter</strong>.</p><p>Vim jumps to the <strong>next</strong> occurrence of <code>pattern</code> after the cursor.</p><h2 id="backward-search" tabindex="-1">Backward Search <a class="header-anchor" href="#backward-search" aria-label="Permalink to &quot;Backward Search&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>?pattern</span></span></code></pre></div><p>Vim jumps to the <strong>previous</strong> occurrence of <code>pattern</code> before the cursor.</p><hr><h1 id="navigating-search-results" tabindex="-1">Navigating Search Results <a class="header-anchor" href="#navigating-search-results" aria-label="Permalink to &quot;Navigating Search Results&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>n</code></td><td>Jump to <strong>next</strong> match</td></tr><tr><td><code>N</code></td><td>Jump to <strong>previous</strong> match</td></tr></tbody></table><p>After a forward search (<code>/</code>):</p><ul><li><code>n</code> goes forward</li><li><code>N</code> goes backward</li></ul><p>After a backward search (<code>?</code>):</p><ul><li><code>n</code> goes backward</li><li><code>N</code> goes forward</li></ul><hr><h1 id="search-highlighting" tabindex="-1">Search Highlighting <a class="header-anchor" href="#search-highlighting" aria-label="Permalink to &quot;Search Highlighting&quot;">​</a></h1><p>By default, matches are highlighted.</p><p>To <strong>remove highlighting temporarily</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:noh</span></span></code></pre></div><p>Short for <code>:nohlsearch</code> (no highlight search).</p><p>To <strong>disable highlighting permanently</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:set nohlsearch</span></span></code></pre></div><p>To <strong>enable it again</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:set hlsearch</span></span></code></pre></div><hr><h1 id="incremental-search" tabindex="-1">Incremental Search <a class="header-anchor" href="#incremental-search" aria-label="Permalink to &quot;Incremental Search&quot;">​</a></h1><p>Enable this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:set incsearch</span></span></code></pre></div><p>Now as you type your search pattern, Vim jumps to the first match immediately.</p><p>It updates as you type more characters.</p><hr><h1 id="case-sensitivity" tabindex="-1">Case Sensitivity <a class="header-anchor" href="#case-sensitivity" aria-label="Permalink to &quot;Case Sensitivity&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Setting</th><th>Effect</th></tr></thead><tbody><tr><td><code>:set ignorecase</code></td><td>Make search case-insensitive</td></tr><tr><td><code>:set smartcase</code></td><td>If pattern has uppercase, be case-sensitive; otherwise, ignore case</td></tr></tbody></table><p>Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/hello     → matches &quot;hello&quot;, &quot;Hello&quot;, &quot;HELLO&quot; (with ignorecase)</span></span>
<span class="line"><span>/Hello     → matches only &quot;Hello&quot; (with smartcase)</span></span></code></pre></div><hr><h1 id="searching-for-the-current-word" tabindex="-1">Searching for the Current Word <a class="header-anchor" href="#searching-for-the-current-word" aria-label="Permalink to &quot;Searching for the Current Word&quot;">​</a></h1><p>Place the cursor on a word, then press:</p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>*</code></td><td>Search <strong>forward</strong> for the word under cursor</td></tr><tr><td><code>#</code></td><td>Search <strong>backward</strong> for the word under cursor</td></tr><tr><td><code>g*</code></td><td>Like <code>*</code> but matches partial words</td></tr><tr><td><code>g#</code></td><td>Like <code>#</code> but matches partial words</td></tr></tbody></table><p>These are extremely useful for code navigation.</p><hr><h1 id="using-counts-with-search" tabindex="-1">Using Counts with Search <a class="header-anchor" href="#using-counts-with-search" aria-label="Permalink to &quot;Using Counts with Search&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>3n</code></td><td>Go to 3rd next match</td></tr><tr><td><code>2N</code></td><td>Go to 2nd previous match</td></tr></tbody></table><hr><h1 id="combining-search-with-operators" tabindex="-1">Combining Search with Operators <a class="header-anchor" href="#combining-search-with-operators" aria-label="Permalink to &quot;Combining Search with Operators&quot;">​</a></h1><p>This is where search becomes extremely powerful.</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>d/foo</code></td><td>Delete from cursor to next occurrence of <code>foo</code></td></tr><tr><td><code>c?bar</code></td><td>Change from cursor back to <code>bar</code></td></tr><tr><td><code>y/hello</code></td><td>Yank from cursor to next <code>hello</code></td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>d/function    Delete everything up to the next occurrence of &quot;function&quot;</span></span>
<span class="line"><span>c?return      Change everything back to &quot;return&quot;</span></span>
<span class="line"><span>y/}           Yank everything up to the next closing brace</span></span></code></pre></div><hr><h1 id="search-history" tabindex="-1">Search History <a class="header-anchor" href="#search-history" aria-label="Permalink to &quot;Search History&quot;">​</a></h1><p>Vim remembers your previous searches.</p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>/</code> then <code>↑</code></td><td>Browse previous searches</td></tr><tr><td><code>?</code> then <code>↑</code></td><td>Browse previous searches</td></tr></tbody></table><p>Press <code>↑</code> and <code>↓</code> to cycle through history.</p><p>Press <strong>Enter</strong> to repeat a previous search.</p><hr><h1 id="special-characters-in-searches" tabindex="-1">Special Characters in Searches <a class="header-anchor" href="#special-characters-in-searches" aria-label="Permalink to &quot;Special Characters in Searches&quot;">​</a></h1><p>Some characters have special meaning in search patterns.</p><p>To search for them literally, <strong>escape</strong> them with <code>\\</code>:</p><table tabindex="0"><thead><tr><th>Character</th><th>Meaning</th><th>To Search Literally</th></tr></thead><tbody><tr><td><code>.</code></td><td>Any character</td><td><code>\\.</code></td></tr><tr><td><code>*</code></td><td>Zero or more</td><td><code>\\*</code></td></tr><tr><td><code>^</code></td><td>Start of line</td><td><code>\\^</code></td></tr><tr><td><code>$</code></td><td>End of line</td><td><code>\\$</code></td></tr><tr><td><code>[</code></td><td>Character class</td><td><code>\\[</code></td></tr><tr><td><code>\\</code></td><td>Escape character</td><td><code>\\\\</code></td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Action</th><th>Command</th></tr></thead><tbody><tr><td>Search forward</td><td><code>/pattern</code></td></tr><tr><td>Search backward</td><td><code>?pattern</code></td></tr><tr><td>Next match</td><td><code>n</code></td></tr><tr><td>Previous match</td><td><code>N</code></td></tr><tr><td>Search word under cursor</td><td><code>*</code> / <code>#</code></td></tr><tr><td>Clear highlight</td><td><code>:noh</code></td></tr><tr><td>Case insensitive</td><td><code>:set ignorecase</code></td></tr><tr><td>Incremental search</td><td><code>:set incsearch</code></td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>/</code> searches forward, <code>?</code> searches backward.</li><li><code>n</code> and <code>N</code> navigate through matches.</li><li><code>*</code> and <code>#</code> search for the word under the cursor instantly.</li><li>Combine search with <code>d</code>, <code>c</code>, <code>y</code> for powerful edits.</li><li><code>:noh</code> clears search highlighting.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and search for a common word using <code>/</code>.</li><li>Navigate through matches with <code>n</code> and <code>N</code>.</li><li>Place the cursor on a word and press <code>*</code> to search forward.</li><li>Use <code>d/function</code> to delete up to a function definition.</li><li>Search with <code>:set incsearch</code> enabled to see live results.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./15-insert-commands.html"><strong>Chapter 15 — Insert Commands</strong></a></p><p>Learn all the ways to enter and exit insert mode efficiently.</p>`,85)])])}const g=t(d,[["render",c]]);export{u as __pageData,g as default};
